#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* l1,
                                  global float* l2,
                                  global float* conn,
                                  global float* partial_sum,
                                  local float* local_mem,
                                  local float* local_conn,
                                  int n1,
                                  int n2) {
    int j = get_global_id(1);
    int k_block = get_global_id(0);

    if (j >= 1 && j <= n2) {
        float sum = 0.0f;

        int start_k = k_block * BLOCK_SIZE;
        int end_k = start_k + BLOCK_SIZE;

        for (int k = start_k; k < end_k && k <= n1; k++) {
            sum += conn[k * (n2 + 1) + j] * l1[k];
        }

        partial_sum[k_block * n2 + (j - 1)] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(global float* delta,
                                    int ndelta,
                                    global float* ly,
                                    int nly,
                                    global float* w,
                                    global float* oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float new_dw = (0.3f * delta[j] * ly[k]) + (0.3f * oldw[k * (ndelta + 1) + j]);
        w[k * (ndelta + 1) + j] += new_dw;
        oldw[k * (ndelta + 1) + j] = new_dw;
    }
}
